#include<stdio.h>

// Function prototype
int add(int, int);

// Function definition
int add(int a, int b) {
    int sum;
    sum = a + b;
    return sum;
}

// Main function
int main() {
    int result;
    result = add(5, 3);  // Function call
    printf("Sum = %d", result);
    return 0;
}

#include<stdio.h>

// Function to swap two numbers (call by reference)
void swap(int *x, int *y) {
    int temp;
    temp = *x;    // Store value at address x
    *x = *y;      // Put value at y into x
    *y = temp;   // Put temp into y
}

int main() {
    int a = 10, b = 20;
    printf("Before swap: a = %d, b = %d\n", a, b);
    swap(&a, &b);  // Pass addresses
    printf("After swap: a = %d, b = %d\n", a, b);
    return 0;
}

#include<stdio.h>

// Recursive function to find factorial
int factorial(int n) {
    // Base case: stop condition
    if (n == 0 || n == 1) {
        return 1;
    }
    // Recursive case
    return n * factorial(n - 1);
}

int main() {
    int num = 5;
    int result = factorial(num);
    printf("Factorial of %d is %d", num, result);
    return 0;
}

#include<stdio.h>

// Function to check if number is positive, negative, or zero
void checkNumber(int num) {
    if (num > 0) {
        printf("Positive number\n");
        return;  // Early return
    }
    if (num < 0) {
        printf("Negative number\n");
        return;  // Early return
    }
    printf("Zero\n");  // No return needed at end
}

int main() {
    checkNumber(10);
    checkNumber(-5);
    checkNumber(0);
    return 0;
}
